BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?docName ?importingNsName WHERE {
  ?req rdf:type vocab:tmt%20requirement ;
       vocab:NamedElement_name ?reqName .
  FILTER(STRLEN(STR(?reqName)) > 0)

  ?importRel rdf:type vocab:element%20import .
  ?importRel vocab:ElementImport_importingNamespace ?importingNs .
  OPTIONAL { ?importRel vocab:NamedElement_name ?docName . }
  OPTIONAL { ?importRel vocab:ElementImport_importedElement ?importedEl . }

  ?importedEl rdf:type vocab:package .

  ?importingNs vocab:Namespace_ownedMember+ ?req .

  OPTIONAL {
    ?importedEl vocab:NamedElement_name ?importedPkgName .
    BIND(CONCAT("Package:", ?importedPkgName) AS ?docName)
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?reqName ?type WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?reqName .
  OPTIONAL { ?req rdf:type ?type }
  FILTER(CONTAINS(LCASE(STR(?reqName)), LCASE("")))
}
LIMIT 25

